<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

  :root {
    --bg-dark: #1e1e2e;
    --bg-panel: #2d2d3f;
    --bg-window: #313145;
    --bg-header: #252536;
    --bg-taskbar: #1a1a2e;
    --accent: #e95420;
    --accent-hover: #ff6b35;
    --text: #e0e0e0;
    --text-dim: #9a9ab0;
    --border: #444466;
    --hover: rgba(255,255,255,0.06);
    --folder-color: #f0c040;
    --file-color: #7eb8da;
    --radius: 8px;
  }

  body {
    font-family: 'Segoe UI', Cantarell, 'Ubuntu', system-ui, sans-serif;
    overflow: hidden;
    height: 100vh;
    width: 100vw;
    background: var(--bg-dark);
    color: var(--text);
    user-select: none;
  }

  #desktop {
    width: 100vw;
    height: 100vh;
    position: relative;
    background:
      radial-gradient(ellipse at 30% 80%, rgba(233,84,32,0.12) 0%, transparent 50%),
      radial-gradient(ellipse at 80% 20%, rgba(100,120,200,0.10) 0%, transparent 50%),
      linear-gradient(160deg, #1a1a2e 0%, #1e1e2e 40%, #252536 100%);
    overflow: hidden;
  }

  /* ── Taskbar ── */
  #taskbar {
    position: absolute;
    bottom: 0; left: 0; right: 0;
    height: 52px;
    background: var(--bg-taskbar);
    border-top: 1px solid var(--border);
    display: flex;
    align-items: center;
    padding: 0 12px;
    gap: 6px;
    z-index: 9999;
    box-shadow: 0 -2px 20px rgba(0,0,0,0.4);
  }

  .launcher-btn {
    width: 42px; height: 42px;
    border-radius: 10px;
    border: none;
    background: var(--hover);
    color: var(--text);
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s, transform 0.1s;
    position: relative;
  }
  .launcher-btn:hover { background: rgba(255,255,255,0.12); transform: scale(1.08); }
  .launcher-btn:active { transform: scale(0.95); }
  .launcher-btn .icon { font-size: 22px; line-height: 1; }
  .launcher-btn .tooltip {
    position: absolute;
    top: -34px;
    left: 50%;
    transform: translateX(-50%);
    background: #111;
    color: #fff;
    font-size: 11px;
    padding: 3px 8px;
    border-radius: 4px;
    white-space: nowrap;
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.15s;
  }
  .launcher-btn:hover .tooltip { opacity: 1; }

  .taskbar-sep {
    width: 1px; height: 28px;
    background: var(--border);
    margin: 0 6px;
  }

  .taskbar-clock {
    margin-left: auto;
    font-size: 13px;
    color: var(--text-dim);
    font-variant-numeric: tabular-nums;
  }

  /* ── Windows ── */
  .window {
    position: absolute;
    background: var(--bg-window);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    box-shadow: 0 8px 40px rgba(0,0,0,0.5), 0 0 0 1px rgba(255,255,255,0.03);
    display: flex;
    flex-direction: column;
    min-width: 360px;
    min-height: 240px;
    overflow: hidden;
    z-index: 100;
  }

  .window-header {
    height: 38px;
    background: var(--bg-header);
    display: flex;
    align-items: center;
    padding: 0 10px;
    cursor: grab;
    flex-shrink: 0;
    border-bottom: 1px solid var(--border);
  }
  .window-header:active { cursor: grabbing; }

  .window-title {
    flex: 1;
    font-size: 13px;
    font-weight: 600;
    color: var(--text);
    display: flex;
    align-items: center;
    gap: 8px;
  }
  .window-title .wt-icon { font-size: 15px; }

  .win-close {
    width: 28px; height: 28px;
    border-radius: 6px;
    border: none;
    background: transparent;
    color: var(--text-dim);
    cursor: pointer;
    font-size: 16px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.12s, color 0.12s;
  }
  .win-close:hover { background: #c0392b; color: #fff; }

  .window-body {
    flex: 1;
    overflow: auto;
    display: flex;
    flex-direction: column;
  }

  /* ── Files App ── */
  #files-window { width: 520px; height: 400px; }

  .files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 12px;
    background: var(--bg-panel);
    border-bottom: 1px solid var(--border);
    flex-shrink: 0;
  }

  #files-up {
    width: 30px; height: 30px;
    border-radius: 6px;
    border: 1px solid var(--border);
    background: var(--bg-window);
    color: var(--text);
    cursor: pointer;
    font-size: 14px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.12s;
  }
  #files-up:hover { background: var(--hover); }
  #files-up:disabled { opacity: 0.3; cursor: default; }

  #files-path {
    flex: 1;
    background: var(--bg-dark);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 5px 10px;
    font-size: 13px;
    color: var(--text);
    font-family: 'Cascadia Code', 'Fira Code', monospace;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .files-content {
    flex: 1;
    padding: 10px;
    overflow-y: auto;
    display: flex;
    flex-wrap: wrap;
    align-content: flex-start;
    gap: 4px;
  }

  .fs-item {
    width: 90px;
    padding: 8px 4px;
    border-radius: 6px;
    text-align: center;
    cursor: pointer;
    transition: background 0.12s;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
  }
  .fs-item:hover { background: var(--hover); }
  .fs-item .fs-icon { font-size: 32px; line-height: 1; }
  .fs-item .fs-name {
    font-size: 11px;
    word-break: break-all;
    line-height: 1.3;
    max-height: 2.6em;
    overflow: hidden;
  }

  /* ── Notepad App ── */
  #notepad-window { width: 560px; height: 420px; }

  .notepad-tabs-bar {
    display: flex;
    align-items: center;
    background: var(--bg-panel);
    border-bottom: 1px solid var(--border);
    padding: 4px 6px 0;
    gap: 2px;
    flex-shrink: 0;
    overflow-x: auto;
  }

  #tabs {
    display: flex;
    gap: 2px;
    flex: 1;
    overflow-x: auto;
  }

  .tab {
    padding: 6px 14px;
    font-size: 12px;
    border-radius: 6px 6px 0 0;
    background: transparent;
    color: var(--text-dim);
    cursor: pointer;
    white-space: nowrap;
    border: 1px solid transparent;
    border-bottom: none;
    transition: background 0.12s, color 0.12s;
    display: flex;
    align-items: center;
    gap: 6px;
    max-width: 140px;
  }
  .tab:hover { background: var(--hover); }
  .tab.active {
    background: var(--bg-window);
    color: var(--text);
    border-color: var(--border);
  }
  .tab .tab-close {
    font-size: 14px;
    line-height: 1;
    opacity: 0.5;
    transition: opacity 0.1s;
  }
  .tab .tab-close:hover { opacity: 1; color: #e74c3c; }

  #new-tab {
    width: 28px; height: 28px;
    border-radius: 6px;
    border: none;
    background: transparent;
    color: var(--text-dim);
    cursor: pointer;
    font-size: 18px;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    transition: background 0.12s;
  }
  #new-tab:hover { background: var(--hover); color: var(--text); }

  #editor {
    flex: 1;
    width: 100%;
    background: var(--bg-window);
    color: var(--text);
    border: none;
    padding: 12px;
    font-family: 'Cascadia Code', 'Fira Code', 'Consolas', monospace;
    font-size: 14px;
    line-height: 1.6;
    resize: none;
    outline: none;
    tab-size: 4;
  }
  #editor::placeholder { color: var(--text-dim); }

  /* ── Scrollbar ── */
  ::-webkit-scrollbar { width: 8px; height: 8px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: var(--border); border-radius: 4px; }
  ::-webkit-scrollbar-thumb:hover { background: #555577; }

  /* ── Focus ring for windows ── */
  .window.focused { box-shadow: 0 8px 40px rgba(0,0,0,0.6), 0 0 0 1px rgba(233,84,32,0.3); z-index: 200; }

  /* ── Animations ── */
  .window { animation: winOpen 0.2s ease-out; }
  @keyframes winOpen {
    from { opacity: 0; transform: scale(0.95) translateY(10px); }
    to { opacity: 1; transform: scale(1) translateY(0); }
  }
</style>
</head>
<body>

<div id="desktop">
  <!-- Taskbar -->
  <div id="taskbar">
    <button class="launcher-btn" id="open-files" title="Files">
      <span class="icon">📁</span>
      <span class="tooltip">Files</span>
    </button>
    <button class="launcher-btn" id="open-notepad" title="Notepad">
      <span class="icon">📝</span>
      <span class="tooltip">Notepad</span>
    </button>
    <div class="taskbar-sep"></div>
    <div class="taskbar-clock" id="clock"></div>
  </div>

  <!-- Files Window -->
  <div class="window" id="files-window" style="display:none; top:60px; left:80px;">
    <div class="window-header" data-window="files-window">
      <div class="window-title"><span class="wt-icon">📁</span> Files</div>
      <button class="win-close" data-target="files-window">✕</button>
    </div>
    <div class="window-body">
      <div class="files-toolbar">
        <button id="files-up" title="Go up">⬆</button>
        <div id="files-path">/</div>
      </div>
      <div class="files-content" id="files-content"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div class="window" id="notepad-window" style="display:none; top:90px; left:140px;">
    <div class="window-header" data-window="notepad-window">
      <div class="window-title"><span class="wt-icon">📝</span> Notepad</div>
      <button class="win-close" data-target="notepad-window">✕</button>
    </div>
    <div class="window-body">
      <div class="notepad-tabs-bar">
        <div id="tabs"></div>
        <button id="new-tab" title="New Tab">+</button>
      </div>
      <textarea id="editor" placeholder="Start typing..."></textarea>
    </div>
  </div>
</div>

<script>
(function() {
  "use strict";

  /* ═══════════════════════════════════════
     FILESYSTEM DATA
     ═══════════════════════════════════════ */
  const FS = {
    "/": {
      type: "dir",
      children: {
        "bin": {
          type: "dir",
          children: {
            "bash": { type: "file" },
            "ls": { type: "file" },
            "cat": { type: "file" },
            "grep": { type: "file" },
            "vim": { type: "file" },
            "python3": { type: "file" },
            "node": { type: "file" }
          }
        },
        "etc": {
          type: "dir",
          children: {
            "passwd": { type: "file" },
            "hosts": { type: "file" },
            "fstab": { type: "file" },
            "nginx": {
              type: "dir",
              children: {
                "nginx.conf": { type: "file" },
                "sites-enabled": {
                  type: "dir",
                  children: {
                    "default": { type: "file" }
                  }
                }
              }
            },
            "ssh": {
              type: "dir",
              children: {
                "sshd_config": { type: "file" },
                "ssh_config": { type: "file" }
              }
            }
          }
        },
        "home": {
          type: "dir",
          children: {
            "user": {
              type: "dir",
              children: {
                "Documents": {
                  type: "dir",
                  children: {
                    "resume.txt": { type: "file" },
                    "notes.md": { type: "file" },
                    "project-plan.txt": { type: "file" }
                  }
                },
                "Downloads": {
                  type: "dir",
                  children: {
                    "archive.tar.gz": { type: "file" },
                    "image.png": { type: "file" },
                    "setup.sh": { type: "file" }
                  }
                },
                "Pictures": {
                  type: "dir",
                  children: {
                    "wallpaper.jpg": { type: "file" },
                    "screenshot.png": { type: "file" },
                    "vacation": {
                      type: "dir",
                      children: {
                        "beach.jpg": { type: "file" },
                        "mountain.jpg": { type: "file" }
                      }
                    }
                  }
                },
                ".bashrc": { type: "file" },
                ".profile": { type: "file" },
                ".config": {
                  type: "dir",
                  children: {
                    "settings.json": { type: "file" }
                  }
                }
              }
            }
          }
        },
        "usr": {
          type: "dir",
          children: {
            "bin": {
              type: "dir",
              children: {
                "firefox": { type: "file" },
                "code": { type: "file" }
              }
            },
            "share": {
              type: "dir",
              children: {
                "applications": {
                  type: "dir",
                  children: {
                    "firefox.desktop": { type: "file" }
                  }
                },
                "themes": {
                  type: "dir",
                  children: {
                    "Adwaita": { type: "dir", children: {} }
                  }
                }
              }
            },
            "lib": {
              type: "dir",
              children: {
                "x86_64-linux-gnu": { type: "dir", children: {} }
              }
            }
          }
        },
        "var": {
          type: "dir",
          children: {
            "log": {
              type: "dir",
              children: {
                "syslog": { type: "file" },
                "auth.log": { type: "file" },
                "kern.log": { type: "file" }
              }
            },
            "www": {
              type: "dir",
              children: {
                "html": {
                  type: "dir",
                  children: {
                    "index.html": { type: "file" },
                    "style.css": { type: "file" }
                  }
                }
              }
            },
            "tmp": {
              type: "dir",
              children: {}
            }
          }
        }
      }
    }
  };

  /* ═══════════════════════════════════════
     FILESYSTEM HELPERS
     ═══════════════════════════════════════ */
  function resolvePath(pathStr) {
    if (pathStr === "/") return FS["/"];
    const parts = pathStr.split("/").filter(Boolean);
    let node = FS["/"];
    for (const p of parts) {
      if (node.children && node.children[p]) {
        node = node.children[p];
      } else {
        return null;
      }
    }
    return node;
  }

  let currentPath = "/";

  function renderFiles() {
    const node = resolvePath(currentPath);
    if (!node) return;

    document.getElementById("files-path").textContent = currentPath;
    const container = document.getElementById("files-content");
    container.innerHTML = "";

    const upBtn = document.getElementById("files-up");
    upBtn.disabled = currentPath === "/";

    if (!node.children) return;

    const entries = Object.entries(node.children);
    // Sort: directories first, then files, alphabetically
    entries.sort((a, b) => {
      const aIsDir = a[1].type === "dir" ? 0 : 1;
      const bIsDir = b[1].type === "dir" ? 0 : 1;
      if (aIsDir !== bIsDir) return aIsDir - bIsDir;
      return a[0].localeCompare(b[0]);
    });

    for (const [name, entry] of entries) {
      const item = document.createElement("div");
      item.className = "fs-item";
      item.dataset.name = name;
      item.dataset.type = entry.type;

      const icon = document.createElement("div");
      icon.className = "fs-icon";
      icon.textContent = entry.type === "dir" ? "📂" : "📄";

      const label = document.createElement("div");
      label.className = "fs-name";
      label.textContent = name;

      item.appendChild(icon);
      item.appendChild(label);

      item.addEventListener("dblclick", () => {
        if (entry.type === "dir") {
          currentPath = currentPath === "/" ? "/" + name : currentPath + "/" + name;
          renderFiles();
        }
      });

      container.appendChild(item);
    }
  }

  document.getElementById("files-up").addEventListener("click", () => {
    if (currentPath === "/") return;
    const parts = currentPath.split("/").filter(Boolean);
    parts.pop();
    currentPath = parts.length === 0 ? "/" : "/" + parts.join("/");
    renderFiles();
  });

  /* ═══════════════════════════════════════
     NOTEPAD — TABS + localStorage
     ═══════════════════════════════════════ */
  const STORAGE_KEY = "ubuntu_notepad_tabs";

  let tabs = [];
  let activeTabId = null;

  function generateId() {
    return "tab_" + Date.now() + "_" + Math.random().toString(36).substr(2, 6);
  }

  function saveTabs() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
    } catch(e) {}
  }

  function loadTabs() {
    try {
      const data = localStorage.getItem(STORAGE_KEY);
      if (data) {
        const parsed = JSON.parse(data);
        if (Array.isArray(parsed) && parsed.length > 0) {
          tabs = parsed;
          activeTabId = tabs[0].id;
          return;
        }
      }
    } catch(e) {}
    // Default: one empty tab
    tabs = [{ id: generateId(), title: "Untitled", content: "" }];
    activeTabId = tabs[0].id;
  }

  function renderTabs() {
    const container = document.getElementById("tabs");
    container.innerHTML = "";

    for (const tab of tabs) {
      const el = document.createElement("div");
      el.className = "tab" + (tab.id === activeTabId ? " active" : "");
      el.dataset.tabId = tab.id;

      const titleSpan = document.createElement("span");
      titleSpan.textContent = tab.title;
      titleSpan.style.maxWidth = "100px";
      titleSpan.style.overflow = "hidden";
      titleSpan.style.textOverflow = "ellipsis";
      titleSpan.style.whiteSpace = "nowrap";

      const closeBtn = document.createElement("span");
      closeBtn.className = "tab-close";
      closeBtn.textContent = "✕";
      closeBtn.addEventListener("click", (e) => {
        e.stopPropagation();
        closeTab(tab.id);
      });

      el.appendChild(titleSpan);
      el.appendChild(closeBtn);

      el.addEventListener("click", () => {
        switchTab(tab.id);
      });

      container.appendChild(el);
    }

    updateEditor();
  }

  function updateEditor() {
    const active = tabs.find(t => t.id === activeTabId);
    const editor = document.getElementById("editor");
    if (active) {
      editor.value = active.content;
    } else {
      editor.value = "";
    }
  }

  function switchTab(id) {
    // Save current tab content before switching
    const current = tabs.find(t => t.id === activeTabId);
    if (current) {
      current.content = document.getElementById("editor").value;
      saveTabs();
    }
    activeTabId = id;
    renderTabs();
  }

  function closeTab(id) {
    const idx = tabs.findIndex(t => t.id === id);
    if (idx === -1) return;

    // Save current content
    const current = tabs.find(t => t.id === activeTabId);
    if (current) {
      current.content = document.getElementById("editor").value;
    }

    tabs.splice(idx, 1);

    if (tabs.length === 0) {
      // Create a new empty tab if all closed
      const newTab = { id: generateId(), title: "Untitled", content: "" };
      tabs.push(newTab);
      activeTabId = newTab.id;
    } else if (activeTabId === id) {
      activeTabId = tabs[Math.min(idx, tabs.length - 1)].id;
    }

    saveTabs();
    renderTabs();
  }

  function createNewTab() {
    // Save current content
    const current = tabs.find(t => t.id === activeTabId);
    if (current) {
      current.content = document.getElementById("editor").value;
    }

    const newTab = { id: generateId(), title: "Untitled", content: "" };
    tabs.push(newTab);
    activeTabId = newTab.id;
    saveTabs();
    renderTabs();
    document.getElementById("editor").focus();
  }

  document.getElementById("new-tab").addEventListener("click", createNewTab);

  // Save content on input
  document.getElementById("editor").addEventListener("input", () => {
    const active = tabs.find(t => t.id === activeTabId);
    if (active) {
      active.content = document.getElementById("editor").value;
      // Update title if content exists
      if (active.content.length > 0 && active.title === "Untitled") {
        active.title = active.content.split("\n")[0].substring(0, 20) || "Untitled";
        renderTabs();
      }
      saveTabs();
    }
  });

  /* ═══════════════════════════════════════
     WINDOW MANAGEMENT
     ═══════════════════════════════════════ */
  let topZ = 100;

  function openWindow(id) {
    const win = document.getElementById(id);
    win.style.display = "flex";
    win.style.animation = "none";
    win.offsetHeight; // reflow
    win.style.animation = "";
    focusWindow(win);
  }

  function closeWindow(id) {
    const win = document.getElementById(id);
    win.style.display = "none";

    // If closing notepad, save current tab content
    if (id === "notepad-window") {
      const active = tabs.find(t => t.id === activeTabId);
      if (active) {
        active.content = document.getElementById("editor").value;
        saveTabs();
      }
    }
  }

  function focusWindow(win) {
    document.querySelectorAll(".window").forEach(w => w.classList.remove("focused"));
    win.classList.add("focused");
    topZ++;
    win.style.zIndex = topZ;
  }

  // Close buttons
  document.querySelectorAll(".win-close").forEach(btn => {
    btn.addEventListener("click", () => {
      const target = btn.dataset.target;
      closeWindow(target);
    });
  });

  // Launcher buttons
  document.getElementById("open-files").addEventListener("click", () => openWindow("files-window"));
  document.getElementById("open-notepad").addEventListener("click", () => openWindow("notepad-window"));

  // Focus on click
  document.querySelectorAll(".window").forEach(win => {
    win.addEventListener("mousedown", () => focusWindow(win));
  });

  /* ═══════════════════════════════════════
     DRAGGABLE WINDOWS
     ═══════════════════════════════════════ */
  document.querySelectorAll(".window-header").forEach(header => {
    let isDragging = false;
    let startX, startY, origX, origY;

    header.addEventListener("mousedown", (e) => {
      if (e.target.classList.contains("win-close")) return;
      const win = header.closest(".window");
      isDragging = true;
      startX = e.clientX;
      startY = e.clientY;
      origX = win.offsetLeft;
      origY = win.offsetTop;
      focusWindow(win);
      e.preventDefault();
    });

    document.addEventListener("mousemove", (e) => {
      if (!isDragging) return;
      const dx = e.clientX - startX;
      const dy = e.clientY - startY;
      const win = header.closest(".window");
      win.style.left = (origX + dx) + "px";
      win.style.top = (origY + dy) + "px";
    });

    document.addEventListener("mouseup", () => {
      isDragging = false;
    });
  });

  /* ═══════════════════════════════════════
     CLOCK
     ═══════════════════════════════════════ */
  function updateClock() {
    const now = new Date();
    const h = now.getHours().toString().padStart(2, "0");
    const m = now.getMinutes().toString().padStart(2, "0");
    document.getElementById("clock").textContent = h + ":" + m;
  }
  updateClock();
  setInterval(updateClock, 30000);

  /* ═══════════════════════════════════════
     INIT
     ═══════════════════════════════════════ */
  renderFiles();
  loadTabs();
  renderTabs();

})();
